\"unit\":\"px\",\"size\":\"30\"}},\"elements\":[],\"widgetType\":\"heading\"},{\"id\":\"3b7cd493\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>We are excited to celebrate our wedding with you on the 23rd of December, 2018. We hope you enjoy the nice, slightly chilly, Florida weather aboard the StarShip II Yacht in Tampa, FL. Bring a light sweater.<\\/p><p>While we love to watch children run and play, this is an adults only kind of day!<\\/p><p>Girls, dress up and let your hair down, there are two decks and we get a whole one all to ourselves!<\\/p><p>Please don\'t hesitate to ask us anything on your mind. We can\'t wait to see you all soon!<\\/p><p>- Hiba &amp; Waseem<\\/p><p>P.S. This website was built by yours truly (Hiba) :)<\\/p>\",\"typography_typography\":\"custom\",\"typography_font_size\":{\"unit\":\"px\",\"size\":26},\"typography_font_family\":\"Courgette\",\"typography_line_height\":{\"unit\":\"em\",\"size\":1.6},\"_padding\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"5\",\"left\":\"0\",\"isLinked\":false},\"typography_font_weight\":\"600\",\"align_mobile\":\"center\",\"typography_font_size_tablet\":{\"unit\":\"px\",\"size\":\"14\"},\"typography_font_size_mobile\":{\"unit\":\"px\",\"size\":\"15\"},\"typography_line_height_mobile\":{\"unit\":\"em\",\"size\":\"1.7\"},\"_padding_tablet\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":true},\"text_color\":\"#777777\",\"align\":\"left\"},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false},{\"id\":\"64d3e4d8\",\"elType\":\"column\",\"settings\":{\"_column_size\":50,\"_inline_size\":\"58.860\",\"border_width\":{\"unit\":\"px\",\"top\":\"10\",\"right\":\"10\",\"bottom\":\"10\",\"left\":\"10\",\"isLinked\":true},\"border_color\":\"#ffffff\",\"box_shadow_box_shadow\":{\"horizontal\":0,\"vertical\":0,\"blur\":\"40\",\"spread\":0,\"inset\":\"\",\"color\":\"rgba(0,0,0,0.5)\"},\"margin\":{\"unit\":\"px\",\"top\":\"-110\",\"right\":\"0\